<?php session_start(); header("Content-Type: application/json"); if(!isset($_SESSION["usuario_id"])){ echo json_encode(["error"=>"No autorizado"]); exit; } try{ $c=new mysqli("localhost","miagenda","miagenda123$","miagenda"); $u=(int)$_SESSION["usuario_id"]; $r1=$c->query("SELECT COUNT(*) as t FROM tareas WHERE usuario_id=$u AND completada=0"); $p=$r1->fetch_assoc()["t"]; $r2=$c->query("SELECT COUNT(*) as t FROM tareas WHERE usuario_id=$u AND completada=1 AND YEARWEEK(fecha_actualizacion)=YEARWEEK(NOW())"); $c2=$r2->fetch_assoc()["t"]; $r3=$c->query("SELECT COUNT(*) as t FROM actividades WHERE usuario_id=$u AND tipo=\"examen\" AND fecha_entrega BETWEEN CURDATE() AND DATE_ADD(CURDATE(),INTERVAL 7 DAY)"); $e=$r3->fetch_assoc()["t"]; $r4=$c->query("SELECT COUNT(*) as t FROM tareas WHERE usuario_id=$u"); $tot=$r4->fetch_assoc()["t"]; $prom=$tot>0?round(($c2/$tot)*100):0; echo json_encode(["pendientes"=>$p,"completadas"=>$c2,"examenes"=>$e,"promedio"=>$prom]); $c->close(); }catch(Exception $ex){ echo json_encode(["error"=>$ex->getMessage()]); } ?>
